    'schadenfreude': {
        1: { title: "마라맛 문제적 집착 폭주자", body: ["이상한 고집을 부리고 헛소리를 시전하며 폭주 기관차입니다. 남들의 시선 따위 가뿐히 무시하며 문제적 집착계의 독보적 빌런으로 활약 중이죠.", "안하무인의 결정체. 본인만 즐겁고 세상 사람들은 다 속이 터지는 극한의 이기주의를 보여줍니다."], insight: "팩트폭행: 그렇게 혼자 막 나가다가는 결국 길바닥에 나앉고 주변에 아무도 없을 겁니다." },
        2: { title: "찌질한 문제적 집착 방구석 여포", body: ["현실에서는 한없이 작아지면서, 음지에서 이상한 고집을 부리고 헛소리를 시전하며 찌질함의 아이콘입니다.", "문제적 집착 상황만 오면 혼자 소설 10권을 쓰며 전전긍긍하지만 겉으로는 아닌 척 태연한 연기를 펼칩니다."], insight: "팩트폭행: 혼자 상상의 나래 펼치고 음침하게 굴지 말고 밖으로 좀 나가세요." },
        3: { title: "해맑은 문제적 집착 시한폭탄", body: ["아무 생각 없이 이상한 고집을 부리고 헛소리를 시전하며 눈치 없는 베짱이 멘탈의 소유자.", "문제적 집착에 대해 심각함을 1도 모르고 언제나 회피하고 도망갈 마인드 세팅이 되어 있습니다."], insight: "팩트폭행: 철딱서니 없는 그 해맑음, 조만간 금융 치료나 지옥 불 맛으로 갚게 될 겁니다." },
        4: { title: "고답이 문제적 집착 대마왕", body: ["본인의 꽉 막힌 철학으로 이상한 고집을 부리고 헛소리를 시전하며 주변 사람들을 미치고 팔짝 뛰게 만드는 재능이 있습니다.", "문제적 집착에 관해서는 남의 말은 귓등으로도 안 듣고 자기가 무조건 맞다고 우기는 꼰대입니다."], insight: "팩트폭행: 당신이 옳다는 오만함을 버리지 않으면 늙어서 고독사하기 딱 좋습니다." },
        5: { title: "얄미운 문제적 집착 미꾸라지", body: ["책임질 일이 생기자마자 핑계 대며 이상한 고집을 부리고 헛소리를 시전하며 요리조리 잘도 빠져나가는 얍삽함의 극치.", "문제적 집착 상황에서 본인이 손해 볼 것 같으면 바로 잠수 타거나 남에게 독박을 씌우는 달인입니다."], insight: "팩트폭행: 계속 그렇게 박쥐처럼 살다가는 어느 쪽에서도 환영받지 못할 겁니다." },
        6: { title: "오지랖 문제적 집착 오작동러", body: ["나서지 말아야 할 때 꼭 나서서 이상한 고집을 부리고 헛소리를 시전하며 상황을 더 최악으로 망쳐놓는 마이너스의 손.", "문제적 집착에 불필요하게 참견하여 남들 피곤하게 만들면서 정작 본인은 도와줬다고 착각합니다."], insight: "팩트폭행: 제발 남 신경 끌어주시고 당신 앞가림이나 똑바로 하십시오." },
        7: { title: "피도 눈물도 없는 문제적 집착 로봇", body: ["일말의 동정심도 없이 이상한 고집을 부리고 헛소리를 시전하며 무자비하게 상황을 칼질해버리는 인성 파탄자.", "타인의 고통과 비명소리는 자체 음소거 처리하고, 오로지 문제적 집착에서 본인의 목적과 이득만 빨아먹습니다."], insight: "팩트폭행: 팩트를 앞세워 패버리는 데서 희열을 느끼나요? 아주 질이 나쁩니다." },
        8: { title: "통제광 문제적 집착 보스", body: ["내 맘대로 안 되면 눈이 돌아가서 이상한 고집을 부리고 헛소리를 시전하며 극한의 갑질을 시전하는 폭군 마인드.", "자기가 정해둔 문제적 집착 규칙을 남들이 안 따르면 무조건 적폐로 간주하고 보복하는 쪼잔함이 있습니다."], insight: "팩트폭행: 당신은 독재자가 아닙니다. 계속 완장질하면 쿠데타 맞고 쫓겨날 겁니다." },
        9: { title: "회피형 문제적 집착 망상가", body: ["문제를 직면하기는커녕 이상한 고집을 부리고 헛소리를 시전하며 상상 속으로 도피해버리는 전형적인 정신 승리의 거장.", "현실의 문제적 집착 엉망진창인데 본인만 평화롭다고 착각하며, 문제를 지적하면 오히려 화를 냅니다."], insight: "팩트폭행: 동화책에서 그만 빠져나오세요. 회피한다고 망한 현실이 복구되진 않습니다." },
    },
